using System.Collections; using System.Collections.Generic; using UnityEngine; public class EnemyManager : MonoBehaviour { private Rigidbody2D rb2D; private SpriteRenderer spriteRenderer; private Transform player; [SerializeField] private float speed = 3f; [SerializeField] private float detectionRange = 10f; [SerializeField] private float health = 30f; private float currentHealth; void Start() { rb2D = GetComponent<Rigidbody2D>(); spriteRenderer = GetComponent<SpriteRenderer>(); player = FindObjectOfType<PlayerManager>()?.transform; currentHealth = health; } void Update() { if (player == null) return; float distanceToPlayer = Vector2.Distance(transform.position, player.position); if (distanceToPlayer < detectionRange) { ChasePlayer(); } else { rb2D.velocity = Vector2.zero; } } private void ChasePlayer() { Vector2 direction = ((Vector2)player.position - (Vector2)transform.position).normalized; rb2D.velocity = direction * speed; if (direction.x < 0) { spriteRenderer.flipX = true; } else if (direction.x > 0) { spriteRenderer.flipX = false; } } public void TakeDamage(float damage) { currentHealth -= damage; if (currentHealth <= 0) { Destroy(gameObject); } } }